import React, { useState, useEffect, useCallback } from 'react';
import { devicesAPI, actionsAPI } from '../utils/api';
import RiskBadge from '../components/RiskBadge';

const RISK_FILTERS = ['ALL', 'CRITICAL', 'HIGH', 'MEDIUM', 'SAFE', 'UNKNOWN'];

function ActionModal({ device, onClose, onDone }) {
  const [reason, setReason] = useState('');
  const [loading, setLoading] = useState(false);

  const doBlock = async () => {
    setLoading(true);
    try {
      await actionsAPI.blockDevice({ vendor_id: device.vendor_id, product_id: device.product_id, serial_number: device.serial_number, device_name: device.device_name, reason: reason || 'Blocked by administrator' });
      onDone('blocked');
    } finally { setLoading(false); }
  };
  const doWhitelist = async () => {
    setLoading(true);
    try {
      await actionsAPI.whitelistDevice({ vendor_id: device.vendor_id, product_id: device.product_id, serial_number: device.serial_number, device_name: device.device_name, notes: reason });
      onDone('whitelisted');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(2,4,8,0.85)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 100, backdropFilter: 'blur(4px)' }}>
      <div className="animate-slide-in-up" style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-glow)', width: '420px', position: 'relative' }}>
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '2px', background: 'linear-gradient(90deg, var(--accent-blue), var(--accent-cyan))' }} />
        <div style={{ padding: '20px 22px', borderBottom: '1px solid var(--border-dim)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '10px', color: 'var(--accent-blue)', letterSpacing: '0.15em' }}>◈ DEVICE ACTION CONSOLE</span>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text-dim)', cursor: 'pointer', fontSize: '14px' }}>✕</button>
        </div>

        <div style={{ padding: '18px 22px' }}>
          {/* Device info */}
          <div style={{ background: 'var(--bg-deep)', border: '1px solid var(--border-dim)', padding: '14px', marginBottom: '16px' }}>
            {[
              ['DEVICE', device.device_name],
              ['VID', device.vendor_id],
              ['PID', device.product_id],
              ['SERIAL', device.serial_number],
              ['HOST', device.hostname],
              ['USER', device.username],
            ].map(([k, v]) => (
              <div key={k} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.12em' }}>{k}</span>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-primary)', maxWidth: '60%', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{v || '—'}</span>
              </div>
            ))}
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '4px', paddingTop: '8px', borderTop: '1px solid var(--border-dim)' }}>
              <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.12em' }}>RISK</span>
              <RiskBadge level={device.risk_level} />
            </div>
          </div>

          <div style={{ marginBottom: '16px' }}>
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.12em', marginBottom: '6px' }}>REASON / NOTES</div>
            <input className="cyber-input" value={reason} onChange={e => setReason(e.target.value)} placeholder="Enter reason..." />
          </div>

          <div style={{ display: 'flex', gap: '10px' }}>
            <button className="btn btn-success" style={{ flex: 1, justifyContent: 'center' }} onClick={doWhitelist} disabled={loading}>✓ WHITELIST</button>
            <button className="btn btn-danger"  style={{ flex: 1, justifyContent: 'center' }} onClick={doBlock}     disabled={loading}>⊘ BLOCK</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function DevicesPage({ liveEvents }) {
  const [devices, setDevices]     = useState([]);
  const [total, setTotal]         = useState(0);
  const [loading, setLoading]     = useState(true);
  const [search, setSearch]       = useState('');
  const [risk, setRisk]           = useState('ALL');
  const [selected, setSelected]   = useState(null);
  const [toast, setToast]         = useState('');

  const fetchDevices = useCallback(async () => {
    try {
      const r = await devicesAPI.list({ search: search || undefined, risk_level: risk === 'ALL' ? undefined : risk.toLowerCase(), limit: 100 });
      setDevices(r.data.devices); setTotal(r.data.total);
    } finally { setLoading(false); }
  }, [search, risk]);

  useEffect(() => { fetchDevices(); }, [fetchDevices]);
  useEffect(() => { if (liveEvents?.length) fetchDevices(); }, [liveEvents, fetchDevices]);

  const handleDone = (action) => {
    setSelected(null);
    setToast(`Device ${action} successfully`);
    setTimeout(() => setToast(''), 3000);
    fetchDevices();
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
      {toast && (
        <div className="animate-slide-in-right" style={{
          position: 'fixed', top: '20px', right: '20px', zIndex: 200,
          background: 'rgba(0,255,136,0.1)', border: '1px solid rgba(0,255,136,0.4)',
          color: 'var(--accent-green)', fontFamily: "'Space Mono', monospace",
          fontSize: '10px', letterSpacing: '0.1em', padding: '10px 16px',
        }}>✓ {toast.toUpperCase()}</div>
      )}
      {selected && <ActionModal device={selected} onClose={() => setSelected(null)} onDone={handleDone} />}

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.2em', marginBottom: '4px' }}>MODULE // DVM-001</div>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: 'var(--text-primary)' }}>Device Monitor</h1>
        </div>
        <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-dim)' }}>
          {total} RECORDS
        </div>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', alignItems: 'center' }}>
        <input className="cyber-input" style={{ width: '280px' }} value={search} onChange={e => setSearch(e.target.value)} placeholder="SEARCH // name, host, serial, VID..." />
        <div style={{ display: 'flex', gap: '4px' }}>
          {RISK_FILTERS.map(f => (
            <button key={f} onClick={() => setRisk(f)} style={{
              fontFamily: "'Space Mono', monospace", fontSize: '9px', letterSpacing: '0.1em',
              padding: '7px 12px', border: '1px solid',
              cursor: 'pointer', transition: 'all 0.15s',
              background: risk === f ? 'rgba(0,212,255,0.1)' : 'transparent',
              borderColor: risk === f ? 'rgba(0,212,255,0.5)' : 'var(--border-dim)',
              color: risk === f ? 'var(--accent-blue)' : 'var(--text-dim)',
            }}>{f}</button>
          ))}
        </div>
      </div>

      {/* Table */}
      <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-blue), transparent)' }} />
        <div style={{ overflowX: 'auto' }}>
          <table className="data-table">
            <thead>
              <tr>
                {['Device Name', 'VID / PID', 'Serial', 'Drive', 'Endpoint', 'User', 'Risk', 'Time', 'Action'].map(h => (
                  <th key={h}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={9} style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>
                  LOADING TELEMETRY...
                </td></tr>
              ) : !devices.length ? (
                <tr><td colSpan={9} style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>
                  NO RECORDS FOUND
                </td></tr>
              ) : devices.map(d => (
                <tr key={d.id}>
                  <td>
                    <div style={{ fontWeight: '600', color: 'var(--text-primary)', maxWidth: '160px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{d.device_name}</div>
                    <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>{d.device_type}</div>
                  </td>
                  <td>
                    <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--accent-cyan)' }}>{d.vendor_id}</div>
                    <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-dim)' }}>{d.product_id}</div>
                  </td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-dim)', maxWidth: '100px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{d.serial_number}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--accent-blue)' }}>{d.drive_letter || '—'}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-primary)' }}>{d.hostname}</td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-dim)' }}>{d.username}</td>
                  <td><RiskBadge level={d.risk_level} pulse /></td>
                  <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>
                    {d.timestamp ? new Date(d.timestamp).toLocaleString() : '—'}
                  </td>
                  <td>
                    <button className="btn btn-primary" style={{ padding: '4px 12px', fontSize: '9px' }} onClick={() => setSelected(d)}>ACTIONS</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
